INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('c6399081-4957-5e7b-bc07-4ae20386fa8d', 'dfe8d1d4-a2e3-4d88-9a37-f535e4ebf944', 'The candidate''s ___ of the job offer was communicated via email.', '應徵者對工作要約的接受是透過電子郵件傳達的。', 'acceptance', 'expectation', 'collection', 'appearance', 'accept (接受) + -ance (名詞字尾) → acceptance (接受)', '記住 accept 是動詞「接受」，加上字尾 -ance 變成名詞「接受」。', '2026-07-06 16:42:33', '2026-07-06 16:42:33'),
('53efa220-7177-5160-bb02-f458ca103029', '39c62bca-8e62-497c-bba0-3397f3416106', 'The security guard remained ___ throughout the night to prevent any unauthorized entry into the building.', '警衛整晚都保持警覺，以防止任何未經授權進入建築物的行為。', 'alert', 'polite', 'massive', 'ancient', 'alert 為單字，源自法語 alerte，意指「警覺的」或「機敏的」。', '想像看到 A 級 (A-class) 的警報 (alert) 響起，就必須立刻保持警覺。', '2026-07-06 19:42:49', '2026-07-06 19:42:49'),
('963cab82-fd94-5e54-9872-dd5b2f55f41d', 'a151aed3-e353-4d6d-aa17-56b0d24a0c28', 'You should look at this problem from a different ___.', '你應該從不同的角度來看待這個問題。', 'angle', 'color', 'sound', 'smell', 'angle 作為名詞，除了指幾何學中的「角」，也常用來指看待事情的「角度」或「觀點」。', 'angle 的形狀就像一個轉彎的角，換個角度看世界，想法會不一樣。', '2026-07-06 14:10:44', '2026-07-06 14:10:44'),
('f0400887-9d2b-5318-9942-d5f9226071f5', 'a246cf3e-3610-404e-9acd-8c45ea3142a6', 'The zoo has many different ___ such as lions and tigers.', '動物園裡有許多不同的動物，像是獅子和老虎。', 'animals', 'plants', 'people', 'toys', 'anim- (生命、靈魂)', 'anim (生命) + al (字尾) → 具有生命的生物 → 動物', '2026-07-06 14:15:10', '2026-07-06 14:15:10'),
('f415e7e1-a7df-5a5e-ac09-93f9e4ecb9b1', '82ab641e-4d4a-4858-9da0-aec191d4d5fb', 'The political refugee applied for ___ at the embassy to escape persecution in his homeland.', '這位政治難民向大使館申請政治庇護，以逃離家鄉的迫害。', 'asylum', 'justice', 'permission', 'wealth', '字根 a- 表示「不」，syl 表示「掠奪」，a- + syl → 不可被掠奪之地，引申為避難所或政治庇護。', '想像 asylum 的發音有點像 a shelter (一個避難所)，幫助記憶其避難的意思。', '2026-07-07 01:45:27', '2026-07-07 01:45:27'),
('a96774ee-70e1-581f-8e50-3cf637a3fb09', 'c7432433-c622-4908-97f8-a8bd85970c57', 'Eating too much junk food is ___ for your health.', '吃太多垃圾食物對你的健康不好。', 'bad', 'good', 'new', 'fast', '無特定字根，常用於形容品質、狀況或對某事物的影響不佳。', '記住 bad for health → 對健康不好。', '2026-07-07 01:49:21', '2026-07-07 01:49:21'),
('817f2359-4a82-54c1-8e66-218f02d086e9', 'bb56a3e8-f551-4c89-b587-8f5e9bae4654', 'We couldn''t go to the park ___ the weather was too cold.', '我們不能去公園，因為天氣太冷了。', 'because', 'though', 'before', 'after', 'because 由 be + cause (造成) 組成，字面意思是「造成...的原因」。', '因為太冷 → 所以不能去。because 用來連接原因與結果。', '2026-07-07 02:51:02', '2026-07-07 02:51:02'),
('9708640e-6d82-58c9-9c2f-9d7323397f0d', 'b293dbac-05ff-4b8e-b6d5-a6e7825914b2', 'My ___ is older than me, and he is very tall.', '我的哥哥比我大，而且他很高。', 'brother', 'teacher', 'doctor', 'pilot', '此字為單字，無特定字根。', '想像一個好兄弟 (bro) 在你身邊。', '2026-07-07 08:41:48', '2026-07-07 08:41:48'),
('eb41ab0b-0241-5118-ae21-48febb1c6e51', '3be8ea18-5803-49cc-9b4b-e45e8961ea1c', 'We woke up at ___ to watch the beautiful sunrise.', '我們在黎明時分醒來，看著美麗的日出。', 'dawn', 'noon', 'night', 'dusk', 'dawn 作為名詞時表示「黎明」或「破曉」，指太陽升起前的時刻。', '想像太陽「當(dawn)天」升起，就是黎明。', '2026-07-07 02:50:31', '2026-07-07 02:50:31'),
('c7b65e93-4e38-5093-b68a-59bc0b194de1', '64309b29-6fec-4a06-9ade-fa1494cef028', 'I take my ___ for a walk every morning.', '我每天早上都會帶我的狗去散步。', 'dog', 'fish', 'rabbit', 'hamster', '名詞：狗。', 'take ... for a walk (帶...去散步) 通常是帶 dog 去。', '2026-07-07 05:02:14', '2026-07-07 05:02:14'),
('98e5d9d1-0bf6-5fc9-a254-0ff5e39d0d41', 'daebe087-0c69-4281-8219-0895ea7e4002', 'I want to buy a sweet ___ with chocolate on top.', '我想買一個上面有巧克力口味的甜油炸圈餅。', 'doughnut', 'hamburger', 'sandwich', 'salad', 'dough 代表麵糰，nut 在這裡指小圓形的東西 → 麵糰製成的圓形甜點。', '想像圓形的麵糰 (dough) 做成一個小圓圈 (nut) → 油炸圈餅。', '2026-07-07 05:20:31', '2026-07-07 05:20:31'),
('d2f70517-a14b-50a5-ac21-42ee64811a21', '4cf6664b-1850-4bd5-b395-8e798dc19420', 'My brother wants to be an ___ because he loves building robots.', '我哥哥想成為一名工程師，因為他很喜歡建造機器人。', 'engineer', 'doctor', 'teacher', 'farmer', 'engine (引擎) + -er (做某事的人) → 工程師', '想像一個工程師 (engineer) 正在修理一台巨大的引擎 (engine)。', '2026-07-07 03:52:21', '2026-07-07 03:52:21'),
('f6263246-bdf8-5858-85df-ab09468332e5', '187963d7-f42c-4963-8eed-23362b495732', 'He cannot buy that car because it is too ___.', '他買不起那輛車，因為它太貴了。', 'expensive', 'old', 'blue', 'tall', 'ex- (向外) + pend (花費) + -ive (形容詞字尾) → 花費很多的。', '看到 expensive 就想到錢一直往外流，所以很貴。', '2026-07-07 05:22:05', '2026-07-07 05:22:05'),
('e9b8d1d3-9713-5526-ac7a-bbc988356501', '7255ac2b-0d2e-4691-a1d8-ee376c11c430', 'It is a known ___ that the earth goes around the sun.', '地球繞著太陽轉是一個已知的事實。', 'fact', 'dream', 'song', 'gift', 'fact 為名詞，意思為「事實」。', 'Fact 聽起來像「發客」→ 發生在客觀世界的事 → 事實。', '2026-07-07 04:34:06', '2026-07-07 04:34:06'),
('01c3988a-e3ed-55b4-93fc-2be10ae3fe41', 'b5c46ec7-afd1-4dbd-a3a0-66a983dfbf40', 'The ___ works hard on the farm every day.', '那位農夫每天在農場辛勤工作。', 'farmer', 'doctor', 'teacher', 'driver', 'farm (農場) + er (人/者)', 'farm (農場) + er (人) → 農夫', '2026-07-07 05:01:06', '2026-07-07 05:01:06'),
('29a3474e-d80a-59af-92b0-028c8647df99', 'fbf1bc22-9ad9-4a87-9256-4a0fc5e9a81b', 'The witness claimed that he did ___ see the suspect at the scene.', '目擊者聲稱他當時並沒有在現場看到嫌犯。', 'not', 'just', 'only', 'already', '表示否定 (Negative marker)', '放在助動詞 (did) 之後來表達否定。', '2026-07-05 14:18:17', '2026-07-05 14:18:17'),
('0823e935-4d80-538d-b2eb-b9140e4193f1', 'c71bd206-4042-406c-8bc2-46572ad87585', 'Please send this email ___ your supervisor as soon as possible.', '請儘快將這封郵件發送給你的主管。', 'to', 'for', 'with', 'by', '表示方向、目的地或對象的介系詞。', 'to → 向 (對象)', '2026-07-05 10:27:51', '2026-07-05 10:27:51');
